#include<bits/stdc++.h>
using namespace std;
long long a[500010][2],n,d,k,f[500010];
bool check(int g)
{
    memset(f,-0x3f,sizeof(f));
    deque<int> q;
    long long l=max(1ll,d-g),r=d+g;
    f[0]=0;
    long long j=0;
    for(long long i=1;i<=n;i++)
    {
        while(a[i][0]-a[j][0]>=l&&j<i)
        {
            if(f[j]>(-1e9))
            {
                while(!q.empty()&&f[q.back()]<=f[j])
                {
                    q.pop_back();
                }
                q.push_back(j);
            }
            j++;
        }
        while(!q.empty()&&a[i][0]-a[q.front()][0]>r)
        {
            q.pop_front();
        }
        if(!q.empty())
        {
            f[i]=f[q.front()]+a[i][1];
        }
        if(f[i]>=k)
        {
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%lld%lld%lld",&n,&d,&k);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&a[i][0],&a[i][1]);
    }
    long long l=0,r=1e9,best=-1;
    while(l<=r)
    {
        long long mid=(l+r)>>1;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%lld",best);
    return 0;
}
